package com.example.knowledgecollector.web.security;
import com.example.knowledgecollector.application.security.UserService;import com.example.knowledgecollector.web.api.*;import jakarta.servlet.http.HttpServletRequest;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.Map;
@RestController @RequestMapping("/api/v1/users") public class UserController {private final UserService users;public UserController(UserService users){this.users=users;}@GetMapping public ApiResponse<?>list(@RequestParam(required=false)String keyword,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size,HttpServletRequest r){return ok(users.list(keyword,page,size),r);}@GetMapping("/{id}")public ApiResponse<?>get(@PathVariable long id,HttpServletRequest r){return ok(users.get(id),r);}@PostMapping public ApiResponse<?>create(@RequestBody Map<String,Object>b,Authentication a,HttpServletRequest r){return ok(users.create(a.getName(),v(b,"username"),v(b,"displayName"),v(b,"password"),v(b,"role"),bool(b,"enabled",true)),r);}@PutMapping("/{id}")public ApiResponse<?>update(@PathVariable long id,@RequestBody Map<String,Object>b,Authentication a,HttpServletRequest r){return ok(users.update(a.getName(),id,v(b,"displayName"),v(b,"role"),bool(b,"enabled",true)),r);}@PostMapping("/{id}/reset-password")public ApiResponse<?>reset(@PathVariable long id,@RequestBody Map<String,Object>b,Authentication a,HttpServletRequest r){users.resetPassword(a.getName(),id,v(b,"password"));return ok(Map.of("reset",true),r);}private<T>ApiResponse<T>ok(T d,HttpServletRequest r){return ApiResponse.success(d,(String)r.getAttribute(CorrelationIdFilter.ATTRIBUTE_NAME));}private static String v(Map<String,Object>b,String k){return b.get(k)==null?"":String.valueOf(b.get(k));}private static boolean bool(Map<String,Object>b,String k,boolean d){return b.get(k)==null?d:Boolean.parseBoolean(String.valueOf(b.get(k)));}}
